-- RemoteEvents.lua — single source of truth for all RemoteEvents and RemoteFunctions
-- Place in: ReplicatedStorage > Modules > RemoteEvents (ModuleScript)
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService = game:GetService("RunService")

local Remotes = {}

local DEFINITIONS = {
  -- Client -> Server
  RequestSummonHuman = "Event",
  RequestPrank = "Event",
  RequestRebirth = "Function",
  RequestEquipSkin = "Function",
  RequestPurchaseSkinChaos = "Function",
  RequestPurchaseSkinHellTokens = "Function",
  RequestUseDevProduct = "Event",
  RequestEquipPerk = "Function",
  RequestResetPerks = "Function",
  RequestAllocStat = "Function",
  RequestEatFood = "Event",
  RequestDrinkWater = "Event",
  RequestEmote = "Event",
  RequestClaimDaily = "Function",
  RequestSpawnCustomization = "Event",
  RequestAdminCommand = "Function",
  -- Server -> Client
  UpdatePlayerData = "Event",
  PrankRegistered = "Event",
  PrankFailed = "Event",
  LevelUp = "Event",
  PerkSlotEarned = "Event",
  RebirthCompleted = "Event",
  NotifyClient = "Event",
  LeaderboardUpdated = "Event",
  WeatherChanged = "Event",
  EventBroadcast = "Event",
  SurvivalUpdate = "Event",
  ErrorNotify = "Event",  -- generic error/toast channel for failed remote handlers
  DailyAvailable = "Event",  -- server announces daily reward is claimable
  EmoteBroadcast = "Event",  -- server fans out an emote to nearby clients
}

-- Find or create folder under ReplicatedStorage
local folder = ReplicatedStorage:FindFirstChild("RemoteEventsFolder")
if not folder then
  folder = Instance.new("Folder")
  folder.Name = "RemoteEventsFolder"
  folder.Parent = ReplicatedStorage
end

for name, kind in pairs(DEFINITIONS) do
  local existing = folder:FindFirstChild(name)
  if not existing then
    local className = (kind == "Function") and "RemoteFunction" or "RemoteEvent"
    if RunService:IsServer() then
      existing = Instance.new(className)
      existing.Name = name
      existing.Parent = folder
    else
      -- Client waits for server to create
      existing = folder:WaitForChild(name, 10)
    end
  end
  Remotes[name] = existing
end

return Remotes

]])

-- ReplicatedStorage/Modules/SharedUtil.lua
W({'ReplicatedStorage','Modules','SharedUtil'}, 'ModuleScript', [[
-- SharedUtil.lua
-- Tiny utilities used across server scripts. Place in ReplicatedStorage > Modules.

local SharedUtil = {}

-- Wait for a value in _G with a timeout. Avoids deadlocks when a dependency
-- script errors during init.
function SharedUtil.waitForGlobal(name, timeoutSec)
    timeoutSec = timeoutSec or 15
    local deadline = os.clock() + timeoutSec
    while not _G[name] do
        if os.clock() > deadline then
            warn(("[SharedUtil] Timed out waiting for _G.%s after %ds"):format(name, timeoutSec))
            return nil
        end
        task.wait(0.05)
    end
    return _G[name]
end

-- Per-player remote rate limiter. Returns true if the call should proceed.
-- key isolates separate remotes (so RequestRebirth and RequestPurchaseSkinChaos
-- don't share a budget).
local rateLimitState = {}
function SharedUtil.checkRate(player, key, intervalSec)
    if not player then return false end
    local userId = player.UserId
    rateLimitState[userId] = rateLimitState[userId] or {}
    local now = os.clock()
    local last = rateLimitState[userId][key] or 0
    if now - last < (intervalSec or 0.4) then
        return false
    end
    rateLimitState[userId][key] = now
    return true
end

function SharedUtil.clearRate(userId)
    rateLimitState[userId] = nil
end

-- Wrap a server-side handler so any Lua error is caught and reported to the
-- client via ErrorNotify, instead of silently leaving the UI hung.
function SharedUtil.safeHandle(remotes, player, handler, ...)
    local ok, result, err = pcall(handler, ...)
    if not ok then
        warn("[SharedUtil] handler error: " .. tostring(result))
        if remotes and remotes.ErrorNotify and player then
            pcall(function() remotes.ErrorNotify:FireClient(player, "internal_error") end)
        end
        return nil, "internal_error"
    end
    return result, err
end

-- Sliding-window counter. Stores timestamps of recent events; trims older than
-- windowSec. Returns true if appending now would exceed maxCount.
function SharedUtil.slidingExceeds(timestamps, windowSec, maxCount)
    local now = os.clock()
    local i = 1
    while i <= #timestamps do
        if now - timestamps[i] > windowSec then
            table.remove(timestamps, i)
        else
            i = i + 1
        end
    end
    if #timestamps >= maxCount then
        return true
    end
    table.insert(timestamps, now)
    return false
end

return SharedUtil

]])

-- ServerScriptService/AdminSystem.server.lua
W({'ServerScriptService','AdminSystem'}, 'Script', [[
-- AdminSystem.server.lua
-- Admin-only chat commands and remote calls. Edit ADMIN_USERIDS below.
-- Place in: ServerScriptService > AdminSystem (Script)

local Players = game:GetService("Players")
local RunService = game:GetService("RunService")
local DataStoreService = game:GetService("DataStoreService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local Remotes = require(ReplicatedStorage.Modules.RemoteEvents)
local CosmeticConfig = require(ReplicatedStorage.Modules.CosmeticConfig)
local SharedUtil = require(ReplicatedStorage.Modules.SharedUtil)

local DataHandler = SharedUtil.waitForGlobal("KittyRaiserData", 30)
if not DataHandler then return end

-- TODO: replace with real admin UserIds (yours + trusted staff)
local ADMIN_USERIDS = {10878595931}  -- Katoxbt (trainyouragent@gmail.com)

-- Studio auto-admin only fires when running solo (no real teammates).
local function studioSoloMode()
    return RunService:IsStudio() and #Players:GetPlayers() <= 1
end

local function isAdmin(player)
    if table.find(ADMIN_USERIDS, player.UserId) then return true end
    if studioSoloMode() then return true end
    if player:GetAttribute("AdminOverride") == true then return true end
    return false
end

-- Audit log: keep last N admin commands in DataStore for forensics.
local auditStore = DataStoreService:GetDataStore("KittyRaiserAdminAudit_v1")
local function audit(actor, command, args)
    pcall(function()
        local key = os.date("!%Y%m%d") .. "_" .. tostring(actor.UserId)
        auditStore:UpdateAsync(key, function(old)
            old = old or {}
            table.insert(old, {ts = os.time(), cmd = command, args = args})
            while #old > 200 do table.remove(old, 1) end
            return old
        end)
    end)
end

local Commands = {}

local function resolveTarget(arg)
    -- accept UserId number, exact name match, or partial-display-name fallback
    local asId = tonumber(arg)
    if asId then return Players:GetPlayerByUserId(asId) end
    if not arg then return nil end
    -- exact name first to avoid prefix collisions
    local exact = Players:FindFirstChild(arg)
    if exact then return exact end
    for _, p in ipairs(Players:GetPlayers()) do
        if p.Name == arg or p.DisplayName == arg then return p end
    end
    return nil
end

Commands.chaos = function(actor, amount)
    amount = tonumber(amount) or 0
    DataHandler.modify(actor, function(d)
        d.chaosPoints = math.max(0, (d.chaosPoints or 0) + amount)
    end)
    return "chaos +" .. amount
end

Commands.helltokens = function(actor, amount)
    amount = tonumber(amount) or 0
    DataHandler.modify(actor, function(d)
        d.hellTokens = math.max(0, (d.hellTokens or 0) + amount)
    end)
    return "hellTokens +" .. amount
end

Commands.level = function(actor, amount)
    amount = tonumber(amount) or 1
    DataHandler.modify(actor, function(d)
        d.level = math.clamp(amount, 1, 100); d.xp = 0
    end)
    return "level set to " .. amount
end

Commands.skin = function(actor, skinId)
    if type(skinId) ~= "string" or not CosmeticConfig.getSkin(skinId) then
        return "invalid skin id"
    end
    DataHandler.modify(actor, function(d)
        d.ownedSkins = d.ownedSkins or {}
        if not table.find(d.ownedSkins, skinId) then table.insert(d.ownedSkins, skinId) end
        d.equippedSkin = skinId
    end)
    return "skin set " .. tostring(skinId)
end

-- Full reset: writes the schema default, preserving identity fields
Commands.reset = function(actor)
    DataHandler.modify(actor, function(d)
        d.chaosPoints = 0
        d.hellTokens = 0
        d.level = 1
        d.xp = 0
        d.rebirths = 0
        d.perks = {}
        d.unspentStatPoints = 0
        d.stats = {Speed=0,Jump=0,Luck=0,Strength=0,Agility=0}
        d.hunger = 100
        d.thirst = 100
        d.dailyStreak = 0
        d.lastDailyClaim = 0
        d.totalPranks = 0
        d.equippedSkin = "Default"
        d.ownedSkins = {"Default"}
        d.flagCount = 0
        d.suspended = false
    end)
    return "fully reset"
end

Commands.kick = function(actor, targetArg, reason)
    local target = resolveTarget(targetArg)
    if not target then return "not found" end
    target:Kick(reason or "Admin kick")
    return "kicked " .. target.Name
end

Commands.unsuspend = function(actor, targetArg)
    local target = resolveTarget(targetArg)
    if not target then return "not found" end
    DataHandler.modify(target, function(d)
        d.flagCount = 0; d.suspended = false
    end)
    return "unsuspended " .. target.Name
end

local function processChatCommand(player, msg)
    if not msg or msg:sub(1,1) ~= "/" then return end
    if not isAdmin(player) then return end
    local parts = msg:sub(2):split(" ")
    local cmd = parts[1]
    local args = {}
    for i = 2, #parts do args[i-1] = parts[i] end
    local fn = Commands[cmd]
    if not fn then return end
    local ok, result = pcall(fn, player, table.unpack(args))
    if ok then
        Remotes.NotifyClient:FireClient(player, "admin: " .. tostring(result), "success")
    else
        Remotes.NotifyClient:FireClient(player, "admin err: " .. tostring(result), "error")
    end
    audit(player, cmd, args)
end

Players.PlayerAdded:Connect(function(player)
    player.Chatted:Connect(function(msg) processChatCommand(player, msg) end)
end)

if RunService:IsStudio() then
    Players.PlayerAdded:Connect(function(player)
        if studioSoloMode() then
            player:SetAttribute("AdminOverride", true)
            print("[AdminSystem] Studio solo-mode auto-admin granted to", player.Name)
        end
    end)
end

Remotes.RequestAdminCommand.OnServerInvoke = function(player, cmd, ...)
    if not SharedUtil.checkRate(player, "adminCmd", 0.2) then return false, "rate_limited" end
    if not isAdmin(player) then return false, "not_admin" end
    local fn = Commands[cmd]
    if not fn then return false, "unknown_cmd" end
    local args = {...}
    local ok, result = pcall(fn, player, ...)
    audit(player, cmd, args)
    return ok, result
end

return true

]])

-- ServerScriptService/AmbientCrowd.server.lua
W({'ServerScriptService','AmbientCrowd'}, 'Script', [[
-- AmbientCrowd.server.lua v4 — single-manager, 12-15 visible NPCs, distance-based
-- Place in: ServerScriptService > AmbientCrowd. Auto-runs.

local Players = game:GetService("Players")
local Workspace = game:GetService("Workspace")

local TARGET_VISIBLE = 14
local NEAR_RADIUS = 80
local FAR_RADIUS = 200
local DESPAWN_RADIUS = 350
local TICK_INTERVAL = 4
local SPAWN_MIN_SPACING = 8

local crowdFolder = Workspace:FindFirstChild("AmbientCrowd")
if not crowdFolder then
    crowdFolder = Instance.new("Folder")
    crowdFolder.Name = "AmbientCrowd"
    crowdFolder.Parent = Workspace
end

local SHIRT = {
    Color3.fromRGB(200,50,50),Color3.fromRGB(60,130,200),Color3.fromRGB(80,200,90),
    Color3.fromRGB(220,200,80),Color3.fromRGB(180,80,200),Color3.fromRGB(60,60,80),
    Color3.fromRGB(240,240,240),Color3.fromRGB(220,130,60),Color3.fromRGB(255,80,130),
    Color3.fromRGB(50,50,50),
}
local SKIN = {
    Color3.fromRGB(245,205,160),Color3.fromRGB(200,165,130),Color3.fromRGB(160,110,80),
    Color3.fromRGB(120,80,55),Color3.fromRGB(95,65,45),Color3.fromRGB(80,50,35),
}
local LEG = {
    Color3.fromRGB(40,40,80),Color3.fromRGB(80,50,30),Color3.fromRGB(50,50,50),
    Color3.fromRGB(100,100,110),Color3.fromRGB(60,80,50),
}

local function buildPed()
    local m = Instance.new("Model")
    m.Name = "Pedestrian"
    m:SetAttribute("KittyRaiserNPC", true)
    m:SetAttribute("Pranked", false)
    m:SetAttribute("AmbientNPC", true)
    m:SetAttribute("LastWanderTime", os.clock())

    local size = math.random() < 0.2 and 0.7 or 1.0

    local hrp = Instance.new("Part")
    hrp.Name = "HumanoidRootPart"
    hrp.Size = Vector3.new(2*size, 2*size, 1*size)
    hrp.Transparency = 1
    hrp.CanCollide = true     -- HRP must collide for humanoid physics to work
    hrp.Massless = true
    hrp.Parent = m

    local torso = Instance.new("Part")
    torso.Name = "Torso"
    torso.Size = Vector3.new(2*size, 2*size, 1*size)
    torso.Color = SHIRT[math.random(1, #SHIRT)]
    torso.Material = Enum.Material.SmoothPlastic
    torso.CanCollide = false
    torso.Position = hrp.Position
    torso.Parent = m
    local tw = Instance.new("WeldConstraint"); tw.Part0 = hrp; tw.Part1 = torso; tw.Parent = torso

    local head = Instance.new("Part")
    head.Name = "Head"
    head.Shape = Enum.PartType.Ball
    head.Size = Vector3.new(1.5*size, 1.5*size, 1.5*size)
    head.Color = SKIN[math.random(1, #SKIN)]
    head.Material = Enum.Material.SmoothPlastic
    head.CanCollide = false
    head.Position = torso.Position + Vector3.new(0, 1.75*size, 0)
    head.Parent = m
    local hw = Instance.new("WeldConstraint"); hw.Part0 = torso; hw.Part1 = head; hw.Parent = head

    local face = Instance.new("Decal")
    face.Texture = "rbxasset://textures/face.png"
    face.Face = Enum.NormalId.Front
    face.Parent = head

    local legs = Instance.new("Part")
    legs.Name = "Legs"
    legs.Size = Vector3.new(2*size, 2*size, 1*size)
    legs.Color = LEG[math.random(1, #LEG)]
    legs.Material = Enum.Material.SmoothPlastic
    legs.CanCollide = false
    legs.Position = torso.Position + Vector3.new(0, -2*size, 0)
    legs.Parent = m
    local lw = Instance.new("WeldConstraint"); lw.Part0 = torso; lw.Part1 = legs; lw.Parent = legs

    local hum = Instance.new("Humanoid")
    hum.MaxHealth = math.huge
    hum.Health = math.huge
    hum.WalkSpeed = math.random(8, 14)
    hum.JumpPower = 0
    hum.HealthDisplayDistance = 0
    hum.Parent = m

    m.PrimaryPart = hrp
    return m
end

local function isPositionFree(pos)
    for _, c in ipairs(crowdFolder:GetChildren()) do
        local p = c.PrimaryPart
        if p and (p.Position - pos).Magnitude < SPAWN_MIN_SPACING then
            return false
        end
    end
    return true
end

local function spawnNearPlayer(player)
    local char = player.Character
    if not char or not char.PrimaryPart then return nil end
    local origin = char.PrimaryPart.Position
    -- Try a handful of positions before giving up to avoid stacking.
    for _ = 1, 4 do
        local angle = math.random() * math.pi * 2
        local r = math.random(NEAR_RADIUS, FAR_RADIUS)
        local pos = origin + Vector3.new(math.cos(angle) * r, 5, math.sin(angle) * r)
        if isPositionFree(pos) then
            local npc = buildPed()
            npc:PivotTo(CFrame.new(pos))
            npc.Parent = crowdFolder
            return npc
        end
    end
    return nil
end

-- SINGLE MANAGER COROUTINE. Snapshot player positions ONCE per tick instead
-- of looping through Players for every NPC (was O(N*M)).
task.spawn(function()
    while true do
        task.wait(TICK_INTERVAL)
        local playerPositions = {}
        for _, p in ipairs(Players:GetPlayers()) do
            local c = p.Character
            if c and c.PrimaryPart then
                table.insert(playerPositions, c.PrimaryPart.Position)
            end
        end

        local liveCount = 0
        for _, npc in ipairs(crowdFolder:GetChildren()) do
            if npc:IsA("Model") and npc:GetAttribute("AmbientNPC") and not npc:GetAttribute("Pranked") then
                local hrp = npc.PrimaryPart
                if hrp then
                    local closest = math.huge
                    for _, pp in ipairs(playerPositions) do
                        local d = (pp - hrp.Position).Magnitude
                        if d < closest then closest = d end
                    end
                    if closest > DESPAWN_RADIUS then
                        npc:Destroy()
                    else
                        liveCount = liveCount + 1
                        local hum = npc:FindFirstChildOfClass("Humanoid")
                        if hum then
                            local d = Vector3.new(math.random(-20, 20), 0, math.random(-20, 20))
                            hum:MoveTo(hrp.Position + d)
                        end
                    end
                end
            end
        end

        local need = TARGET_VISIBLE - liveCount
        if need > 0 then
            for _, p in ipairs(Players:GetPlayers()) do
                if need <= 0 then break end
                if spawnNearPlayer(p) then need = need - 1 end
            end
        end
    end
end)

print("[AmbientCrowd v4] single-manager mode, target " .. TARGET_VISIBLE .. " NPCs visible")

]])

-- ServerScriptService/AnalyticsHandler.server.lua
W({'ServerScriptService','AnalyticsHandler'}, 'Script', [[
-- AnalyticsHandler.server.lua
-- Centralized analytics event firing. Uses Roblox AnalyticsService where possible,
-- falls back to print() in studio. External adapters (PlayFab, etc.) can hook here.
-- Place in: ServerScriptService > AnalyticsHandler (Script)

local Players = game:GetService("Players")
local AnalyticsService = game:GetService("AnalyticsService")
local RunService = game:GetService("RunService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local GameConfig = require(ReplicatedStorage.Modules.GameConfig)

local Analytics = {}

local sessionStart = {}  -- userId -> os.time()

local function emit(eventName, player, props)
    if not GameConfig.ANALYTICS_ENABLED then return end
    local userId = player and player.UserId or 0
    local payload = {
        event = eventName,
        userId = userId,
        ts = os.time(),
        props = props or {},
    }
    if RunService:IsStudio() then
        print(string.format("[Analytics] %s userId=%d %s",
            eventName, userId, game:GetService("HttpService"):JSONEncode(props or {})))
    end
    -- Roblox built-in funnel tracking (when applicable). Guard against nil player
    -- because session_start fires synchronously and player can be nil for global events.
    pcall(function()
        if player and eventName == "level_up" and props and props.newLevel then
            AnalyticsService:LogProgressionEvent(
                player,
                "MainProgression",
                Enum.AnalyticsProgressionStatus.Complete,
                props.newLevel
            )
        end
    end)
end

function Analytics.sessionStart(player)
    if not player then return end
    sessionStart[player.UserId] = os.clock()
    emit("session_start", player)
end

function Analytics.sessionEnd(player)
    if not player then return end
    local start = sessionStart[player.UserId]
    local duration = start and (os.clock() - start) or 0
    emit("session_end", player, {duration = math.floor(duration)})
    sessionStart[player.UserId] = nil
end

function Analytics.firstSummon(player)
    emit("first_summon", player)
end

function Analytics.firstPrank(player, prankName)
    emit("first_prank", player, {prank = prankName})
end

function Analytics.levelUp(player, newLevel)
    emit("level_up", player, {newLevel = newLevel})
end

function Analytics.rebirth(player, rebirths)
    emit("rebirth_completed", player, {rebirths = rebirths})
end

function Analytics.gamepassPurchased(player, gamepassId)
    emit("gamepass_purchased", player, {gamepassId = gamepassId})
end

function Analytics.devProductPurchased(player, productId)
    emit("devproduct_purchased", player, {productId = productId})
end

Players.PlayerAdded:Connect(function(p) Analytics.sessionStart(p) end)
Players.PlayerRemoving:Connect(function(p) Analytics.sessionEnd(p) end)

_G.KittyRaiserAnalytics = Analytics
return Analytics

]])

-- ServerScriptService/AntiCheat.server.lua
W({'ServerScriptService','AntiCheat'}, 'Script', [[
-- AntiCheat.server.lua
-- Server-side rate limiting + sanity checks. Anti-cheat is server-authoritative.
-- Place in: ServerScriptService > AntiCheat (Script)

local Players = game:GetService("Players")
local RunService = game:GetService("RunService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local GameConfig = require(ReplicatedStorage.Modules.GameConfig)
local SharedUtil = require(ReplicatedStorage.Modules.SharedUtil)

local AntiCheat = {}

-- DataHandler comes up after AntiCheat sometimes; resolve lazily on first flag.
local _dataHandler = nil
local function dh()
    if _dataHandler then return _dataHandler end
    _dataHandler = _G.KittyRaiserData
    return _dataHandler
end

local State = {}

local function getState(userId)
    if not State[userId] then
        State[userId] = {
            lastPrankTime = {},
            prankWindow = {},   -- sliding window of recent prank timestamps
            lastPos = nil,
            lastPosTime = 0,
            flagCount = 0,      -- session flags; persisted flagCount lives in DataHandler
            suspended = false,
        }
    end
    return State[userId]
end

-- Initialize from persisted save when player loads, so cheaters can't reset
-- their flag count by rejoining.
local function initFromSave(player)
    local handler = dh()
    if not handler then return end
    local data = handler.getData(player)
    if not data then return end
    local s = getState(player.UserId)
    s.flagCount = data.flagCount or 0
    s.suspended = (data.suspended == true) or (s.flagCount >= GameConfig.SUSPICIOUS_FLAG_THRESHOLD)
end

Players.PlayerAdded:Connect(function(player)
    -- DataHandler also runs PlayerAdded; wait briefly for it to load
    task.delay(3, function() initFromSave(player) end)
end)

-- ===== Cooldown check (per prank type) =====
function AntiCheat.checkPrankCooldown(player, prankName, cooldownSec)
    local s = getState(player.UserId)
    local now = os.clock()
    local last = s.lastPrankTime[prankName] or 0
    if (now - last) < cooldownSec then
        return false, "cooldown"
    end
    s.lastPrankTime[prankName] = now
    return true, nil
end

-- ===== True sliding-window rate limit =====
-- The previous version trimmed entries older than (now - 1) on every call.
-- That allowed bursts at second boundaries (6 at t=0.0, 6 more at t=1.001).
-- The new version uses SharedUtil.slidingExceeds which keeps a real window.
function AntiCheat.checkRateLimit(player)
    local s = getState(player.UserId)
    if SharedUtil.slidingExceeds(s.prankWindow, 1.0, GameConfig.MAX_PRANKS_PER_SECOND) then
        AntiCheat.flag(player, "rate_limit_exceeded")
        return false, "rate_limited"
    end
    return true, nil
end

-- ===== Distance check =====
function AntiCheat.checkPrankDistance(player, targetPart, maxStuds)
    local char = player.Character
    if not char then return false, "no_character" end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    if not hrp then return false, "no_root" end
    if not targetPart or not targetPart:IsA("BasePart") then return false, "invalid_target" end
    local dist = (hrp.Position - targetPart.Position).Magnitude
    if dist > maxStuds then
        return false, "out_of_range"
    end
    return true, nil
end

-- ===== Teleport detection =====
-- Tightened threshold: top legitimate speed is ~24 walk + ~50 jump arc; we
-- allow MAX_TELEPORT_SPEED_STUDS_PER_SEC = 35 with a small jitter buffer for
-- network lag spikes. Also: prime lastPos on character spawn so the first
-- post-spawn frame can't get a free teleport.
function AntiCheat.checkTeleport(player)
    local char = player.Character
    if not char then return true end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    if not hrp then return true end
    local s = getState(player.UserId)
    local now = os.clock()
    if s.lastPos then
        local dt = math.max(now - s.lastPosTime, 0.001)
        local dist = (hrp.Position - s.lastPos).Magnitude
        local speed = dist / dt
        local maxSpeed = GameConfig.MAX_TELEPORT_SPEED_STUDS_PER_SEC * 2  -- 2x burst headroom for lag
        if speed > maxSpeed and dist > 6 then
            AntiCheat.flag(player, "teleport_detected")
            -- snap them back to keep the cheat from progressing
            pcall(function() hrp.CFrame = CFrame.new(s.lastPos) end)
            return false
        end
    end
    s.lastPos = hrp.Position
    s.lastPosTime = now
    return true
end

-- ===== Validate target NPC =====
-- Adds: Workspace ancestry check, optional ownership check (NPC was summoned by
-- this player). Returns false reason for logging.
function AntiCheat.isValidNPC(targetModel, summoningPlayer)
    if not targetModel or not targetModel:IsA("Model") then return false, "not_model" end
    if not targetModel.Parent or not targetModel:IsDescendantOf(workspace) then
        return false, "not_in_workspace"
    end
    if not targetModel:GetAttribute("KittyRaiserNPC") then return false, "missing_attr" end
    if targetModel:GetAttribute("Pranked") then return false, "already_pranked" end
    if summoningPlayer then
        local summonedBy = targetModel:GetAttribute("SummonedBy")
        -- ambient (non-summoned) NPCs have no SummonedBy and are fair game for anyone
        if summonedBy ~= nil and summonedBy ~= summoningPlayer.UserId then
            return false, "not_owner"
        end
    end
    return true, nil
end

-- ===== Flag a suspicious event =====
-- Persists the new flagCount to the DataHandler so it survives rejoin.
function AntiCheat.flag(player, reason)
    local s = getState(player.UserId)
    s.flagCount = s.flagCount + 1
    warn("[AntiCheat] FLAG", player.Name, reason, "total flags:", s.flagCount)
    if s.flagCount >= GameConfig.SUSPICIOUS_FLAG_THRESHOLD then
        s.suspended = true
        warn("[AntiCheat] Player", player.Name, "suspended for session")
    end
    local handler = dh()
    if handler then
        handler.modify(player, function(d)
            d.flagCount = math.max(d.flagCount or 0, s.flagCount)
            if s.suspended then d.suspended = true end
        end)
    end
end

function AntiCheat.isSuspended(player)
    local s = getState(player.UserId)
    return s.suspended or s.flagCount >= GameConfig.SUSPICIOUS_FLAG_THRESHOLD
end

-- Reset position-tracking on respawn so a death + respawn doesn't trip a
-- false-positive teleport alert.
Players.PlayerAdded:Connect(function(player)
    player.CharacterAdded:Connect(function(char)
        local s = getState(player.UserId)
        local hrp = char:WaitForChild("HumanoidRootPart", 5)
        if hrp then
            s.lastPos = hrp.Position
            s.lastPosTime = os.clock()
        end
    end)
end)

Players.PlayerRemoving:Connect(function(player)
    State[player.UserId] = nil
    SharedUtil.clearRate(player.UserId)
end)

-- Heartbeat teleport check (throttled to 4Hz - sufficient for catching teleports
-- without burning per-frame CPU on every player).
local lastTpCheck = 0
RunService.Heartbeat:Connect(function()
    local now = os.clock()
    if now - lastTpCheck < 0.25 then return end
    lastTpCheck = now
    for _, player in ipairs(Players:GetPlayers()) do
        AntiCheat.checkTeleport(player)
    end
end)

_G.KittyRaiserAntiCheat = AntiCheat
return AntiCheat

]])

