-- ServerScriptService/PerkSystem.server.lua
W({'ServerScriptService','PerkSystem'}, 'Script', [[
-- PerkSystem.server.lua
-- Grants perk slots every 5 levels, presents picker, applies effects, allows reset.
-- Place in: ServerScriptService > PerkSystem (Script)

local Players = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local Remotes = require(ReplicatedStorage.Modules.RemoteEvents)
local GameConfig = require(ReplicatedStorage.Modules.GameConfig)
local PerkConfig = require(ReplicatedStorage.Modules.PerkConfig)
local SharedUtil = require(ReplicatedStorage.Modules.SharedUtil)

local DataHandler = SharedUtil.waitForGlobal("KittyRaiserData", 30)
if not DataHandler then return end

local PerkSystem = {}

-- Equip / pick perk for slot. Sequential rule: slot N can only be equipped if
-- slots 1..N-1 are already filled (no skipping).
Remotes.RequestEquipPerk.OnServerInvoke = function(player, slot, perkId)
    if not SharedUtil.checkRate(player, "equipPerk", GameConfig.REMOTE_RATE_LIMIT_SEC) then
        return false, "rate_limited"
    end
    if type(slot) ~= "number" or type(perkId) ~= "string" or #perkId > 64 then
        return false, "bad_args"
    end
    if slot ~= math.floor(slot) or slot < 1 or slot > 5 then
        return false, "bad_slot"
    end
    local data = DataHandler.getData(player)
    if not data then return false, "no_data" end

    local availableSlots = GameConfig.perkSlotsAtLevel(data.level or 1)
    if slot > availableSlots then return false, "slot_locked" end

    -- enforce sequential claim
    data.perks = data.perks or {}
    for i = 1, slot - 1 do
        if not data.perks[tostring(i)] then return false, "earlier_slot_unfilled" end
    end

    local options = PerkConfig.optionsForSlot(slot)
    if not options or not table.find(options, perkId) then
        return false, "invalid_perk_for_slot"
    end

    DataHandler.modify(player, function(d)
        d.perks = d.perks or {}
        d.perks[tostring(slot)] = perkId
    end)
    PerkSystem.applyStatsToCharacter(player)
    return true, nil
end

Remotes.RequestResetPerks.OnServerInvoke = function(player, useRobux)
    if not SharedUtil.checkRate(player, "resetPerks", 1.0) then return false, "rate_limited" end
    local data = DataHandler.getData(player)
    if not data then return false, "no_data" end
    if useRobux then
        local prodId = GameConfig.DEVPRODUCT_IDS.PERK_RESET
        if prodId == 0 then return false, "robux_product_unset" end
        return false, "use_client_prompt"
    else
        local cost = GameConfig.PERK_RESET_HELLTOKENS
        if cost < 0 or (data.hellTokens or 0) < cost then return false, "not_enough_helltokens" end
        DataHandler.modify(player, function(d)
            d.hellTokens = d.hellTokens - cost
            d.perks = {}
        end)
        return true, nil
    end
end

-- Atomic stat allocation. Re-read inside modify to prevent rapid-double-call
-- from going negative.
Remotes.RequestAllocStat.OnServerInvoke = function(player, statName)
    if not SharedUtil.checkRate(player, "allocStat", GameConfig.REMOTE_RATE_LIMIT_SEC) then
        return false, "rate_limited"
    end
    if type(statName) ~= "string" then return false, "bad_stat" end
    if not table.find(GameConfig.STAT_NAMES, statName) then return false, "bad_stat" end
    local data = DataHandler.getData(player)
    if not data then return false, "no_data" end

    local success
    DataHandler.modify(player, function(d)
        d.stats = d.stats or {}
        local current = d.stats[statName] or 0
        if (d.unspentStatPoints or 0) <= 0 or current >= GameConfig.STAT_MAX then
            success = false
            return
        end
        d.unspentStatPoints = d.unspentStatPoints - 1
        d.stats[statName] = current + 1
        success = true
    end)
    if not success then return false, "no_points_or_maxed" end
    PerkSystem.applyStatsToCharacter(player)
    return true, nil
end

function PerkSystem.applyStatsToCharacter(player)
    local data = DataHandler.getData(player)
    if not data or not data.stats then return end
    local char = player.Character
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return end
    local speedMult = 1 + PerkConfig.sumEffect(data.perks, "speedMult")  -- LightFeet etc
    local baseSpeed = (16 + (data.stats.Speed or 0) * GameConfig.STAT_EFFECTS.Speed.walkSpeedPerPoint) * speedMult
    hum.WalkSpeed = baseSpeed
    hum.JumpPower = 50 + (data.stats.Jump or 0) * GameConfig.STAT_EFFECTS.Jump.jumpPowerPerPoint
    -- Update the survival debuff baseline so reverting after low-vitals uses the boosted value.
    char:SetAttribute("BaseWalkSpeed", baseSpeed)
end

-- Level-up integration. We treat PrankSystem's update to data.level as the
-- single source of truth. The previous design also ran a parallel "watcher"
-- that double-granted stat points on each level. We replace it with a direct
-- LevelUp listener using data attributes.
local lastSeenLevel = {}

local function ensureLevelGrants(player, prevLevel, newLevel)
    if newLevel <= prevLevel then return end
    DataHandler.modify(player, function(d)
        d.unspentStatPoints = (d.unspentStatPoints or 0) + GameConfig.STATS_PER_LEVEL * (newLevel - prevLevel)
    end)
    for newLvl = prevLevel + 1, newLevel do
        if newLvl % GameConfig.PERK_GRANT_EVERY == 0 then
            local slot = math.floor(newLvl / GameConfig.PERK_GRANT_EVERY)
            local options = PerkConfig.optionsForSlot(slot)
            if options and #options > 0 then
                Remotes.PerkSlotEarned:FireClient(player, slot, options)
            end
        end
    end
end

Players.PlayerAdded:Connect(function(player)
    player.CharacterAdded:Connect(function()
        task.wait(0.5)
        PerkSystem.applyStatsToCharacter(player)
    end)
end)

Players.PlayerRemoving:Connect(function(p) lastSeenLevel[p.UserId] = nil end)

-- Throttled change-detector. Idempotent: only fires for the *delta* in level
-- since we last saw it (so it never double-grants for the same level).
task.spawn(function()
    while true do
        task.wait(1)
        for _, player in ipairs(Players:GetPlayers()) do
            local data = DataHandler.getData(player)
            if data then
                local prev = lastSeenLevel[player.UserId]
                if prev == nil then
                    lastSeenLevel[player.UserId] = data.level
                elseif data.level > prev then
                    ensureLevelGrants(player, prev, data.level)
                    lastSeenLevel[player.UserId] = data.level
                end
            end
        end
    end
end)

_G.KittyRaiserPerks = PerkSystem
return PerkSystem

]])

-- ServerScriptService/PrankSystem.server.lua
W({'ServerScriptService','PrankSystem'}, 'Script', [[
-- PrankSystem.server.lua
-- Receives prank requests from client, validates, awards Chaos & XP, fires effect events.
-- Place in: ServerScriptService > PrankSystem (Script)

local Players = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local MarketplaceService = game:GetService("MarketplaceService")

local Remotes = require(ReplicatedStorage.Modules.RemoteEvents)
local PrankConfig = require(ReplicatedStorage.Modules.PrankConfig)
local CosmeticConfig = require(ReplicatedStorage.Modules.CosmeticConfig)
local GameConfig = require(ReplicatedStorage.Modules.GameConfig)
local SharedUtil = require(ReplicatedStorage.Modules.SharedUtil)

local DataHandler = SharedUtil.waitForGlobal("KittyRaiserData", 30)
local AntiCheat = SharedUtil.waitForGlobal("KittyRaiserAntiCheat", 30)
local SummonSystem = SharedUtil.waitForGlobal("KittyRaiserSummon", 30)
if not (DataHandler and AntiCheat and SummonSystem) then
    warn("[PrankSystem] One of DataHandler/AntiCheat/SummonSystem failed to init; aborting")
    return
end

local PrankSystem = {}

local MAX_LEVELUPS_PER_PRANK = 5  -- cap RemoteEvent fan-out from a giant XP grant

-- Cache VIP ownership per player; UserOwnsGamePassAsync hits the network and
-- the result rarely changes within a session.
local vipCache = {}
local function hasVIP(player)
    if vipCache[player.UserId] ~= nil then return vipCache[player.UserId] end
    local vipId = GameConfig.GAMEPASS_IDS.VIP
    if vipId == 0 then vipCache[player.UserId] = false; return false end
    local ok, owns = pcall(function()
        return MarketplaceService:UserOwnsGamePassAsync(player.UserId, vipId)
    end)
    local result = (ok and owns) or false
    vipCache[player.UserId] = result
    return result
end
Players.PlayerRemoving:Connect(function(p) vipCache[p.UserId] = nil end)

local function awardChaosAndXP(player, baseChaos)
    local data = DataHandler.getData(player)
    if not data then return 0, 0 end

    local skinMult = math.max(0, CosmeticConfig.getMultiplier(data.equippedSkin or "Default") or 1)
    local luckStat = (data.stats and data.stats.Luck) or 0
    local weatherMult = (_G.KittyRaiserGetWeatherMult and _G.KittyRaiserGetWeatherMult()) or 1
    local totalMult = GameConfig.computeMultiplier(data.rebirths or 0, hasVIP(player), luckStat)
        * skinMult * weatherMult

    local chaosGained = math.max(0, math.floor(baseChaos * totalMult))

    DataHandler.modify(player, function(d)
        d.chaosPoints = (d.chaosPoints or 0) + chaosGained
        d.totalPranks = (d.totalPranks or 0) + 1
        d.xp = (d.xp or 0) + GameConfig.PRANK_XP_PER_HIT

        local levelUps = 0
        while d.level < GameConfig.LEVEL_CAP
            and d.xp >= GameConfig.xpRequired(d.level)
            and levelUps < MAX_LEVELUPS_PER_PRANK
        do
            d.xp = d.xp - GameConfig.xpRequired(d.level)
            d.level = d.level + 1
            levelUps = levelUps + 1
            local unlocked = {}
            for _, name in ipairs(PrankConfig.Order) do
                if PrankConfig.Pranks[name].unlockLevel == d.level then
                    table.insert(unlocked, name)
                end
            end
            Remotes.LevelUp:FireClient(player, d.level, unlocked)
        end
        -- if we still have surplus XP after the batch, clamp it so subsequent
        -- pranks still benefit from level-ups normally
        if levelUps >= MAX_LEVELUPS_PER_PRANK and d.level < GameConfig.LEVEL_CAP then
            d.xp = math.min(d.xp, GameConfig.xpRequired(d.level) - 1)
        end
    end)
    if _G.KittyRaiserMarkLeaderboardDirty then _G.KittyRaiserMarkLeaderboardDirty() end
    return chaosGained, GameConfig.PRANK_XP_PER_HIT
end

function PrankSystem.handlePrankRequest(player, prankName, targetModel)
    if AntiCheat.isSuspended(player) then
        Remotes.PrankFailed:FireClient(player, "suspended")
        return
    end

    if type(prankName) ~= "string" or #prankName > 32 then
        Remotes.PrankFailed:FireClient(player, "invalid_prank")
        return
    end

    local prank = PrankConfig.getPrank(prankName)
    if not prank then
        Remotes.PrankFailed:FireClient(player, "invalid_prank")
        return
    end

    local data = DataHandler.getData(player)
    if not data then
        Remotes.PrankFailed:FireClient(player, "no_data")
        return
    end

    if data.level < prank.unlockLevel then
        Remotes.PrankFailed:FireClient(player, "level_locked")
        return
    end

    if not AntiCheat.checkRateLimit(player) then
        Remotes.PrankFailed:FireClient(player, "rate_limited")
        return
    end

    if not AntiCheat.checkPrankCooldown(player, prankName, prank.cooldown) then
        Remotes.PrankFailed:FireClient(player, "cooldown")
        return
    end

    -- NPC validity (now requires registry membership + ownership match)
    local valid, vErr = AntiCheat.isValidNPC(targetModel, player)
    if not valid then
        Remotes.PrankFailed:FireClient(player, vErr or "invalid_target")
        return
    end
    if not SummonSystem.isRegistered(targetModel) then
        Remotes.PrankFailed:FireClient(player, "unregistered_target")
        return
    end

    local primary = targetModel.PrimaryPart or targetModel:FindFirstChild("HumanoidRootPart")
    if not primary then
        Remotes.PrankFailed:FireClient(player, "no_primary_part")
        return
    end
    local distOk, distErr = AntiCheat.checkPrankDistance(player, primary, prank.rangeStuds)
    if not distOk then
        Remotes.PrankFailed:FireClient(player, distErr or "out_of_range")
        return
    end

    -- ATOMIC GUARD: claim the NPC BEFORE awarding so two simultaneous pranks
    -- against the same NPC can't both pass validation.
    if not SummonSystem.markPranked(targetModel) then
        Remotes.PrankFailed:FireClient(player, "already_pranked")
        return
    end

    local chaos = awardChaosAndXP(player, prank.baseChaos)

    -- Sanity: never broadcast bogus CFrames
    local cf = primary.CFrame
    if not cf or cf.Position.Magnitude > 100000 then
        cf = CFrame.new(0, 0, 0)
    end

    local fxPayload = {
        prank = prankName,
        targetCFrame = cf,
        chaosGained = chaos,
        screenShake = prank.screenShake or 0,
    }
    Remotes.PrankRegistered:FireClient(player, prankName, targetModel, chaos, fxPayload)

    for _, p in ipairs(Players:GetPlayers()) do
        if p ~= player then
            local pChar = p.Character
            if pChar and pChar.PrimaryPart
                and (pChar.PrimaryPart.Position - primary.Position).Magnitude < 80
            then
                Remotes.PrankRegistered:FireClient(p, prankName, targetModel, 0, fxPayload)
            end
        end
    end
end

Remotes.RequestPrank.OnServerEvent:Connect(function(player, prankName, targetModel)
    PrankSystem.handlePrankRequest(player, prankName, targetModel)
end)

return PrankSystem

]])

-- ServerScriptService/RagdollOnPrank.server.lua
W({'ServerScriptService','RagdollOnPrank'}, 'Script', [[
-- RagdollOnPrank.server.lua
-- When a registered NPC's Pranked attribute flips, ragdoll it + add knockback +
-- spawn coin loot. Place in ServerScriptService.

local Players = game:GetService("Players")
local Workspace = game:GetService("Workspace")
local Debris = game:GetService("Debris")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

require(ReplicatedStorage:WaitForChild("Modules"):WaitForChild("RemoteEvents"))

local function ragdoll(npc, fromPos)
    if not npc or not npc.Parent then return end
    local hum = npc:FindFirstChildOfClass("Humanoid")
    if hum then
        hum.PlatformStand = true
        hum.WalkSpeed = 0
    end
    for _, p in ipairs(npc:GetDescendants()) do
        if p:IsA("BasePart") and not p.Anchored then
            local diff = p.Position - fromPos
            local dir
            if diff.Magnitude < 1e-3 then
                dir = Vector3.new(0, 1, 0)
            else
                dir = diff.Unit
            end
            p.AssemblyLinearVelocity = dir * 60 + Vector3.new(0, 40, 0)
            p.AssemblyAngularVelocity = Vector3.new(
                math.random() * 8 - 4,
                math.random() * 8 - 4,
                math.random() * 8 - 4
            )
        end
    end
    Debris:AddItem(npc, 3)
end

local function spawnCoinLoot(pos, count)
    for _ = 1, count do
        local c = Instance.new("Part")
        c.Shape = Enum.PartType.Cylinder
        c.Size = Vector3.new(0.4, 1.2, 1.2)
        c.Material = Enum.Material.Neon
        c.Color = Color3.fromRGB(255, 215, 0)
        c.CFrame = CFrame.new(
            pos + Vector3.new(math.random()*4-2, 4 + math.random()*2, math.random()*4-2)
        ) * CFrame.Angles(0, 0, math.rad(90))
        c.AssemblyLinearVelocity = Vector3.new(
            (math.random()-0.5)*30,
            math.random()*20+10,
            (math.random()-0.5)*30
        )
        c.CanCollide = true   -- coins now bounce on the ground instead of sinking
        c.Parent = Workspace
        Debris:AddItem(c, 4)
    end
end

local function spawnChaosNumber(pos, amount)
    local part = Instance.new("Part")
    part.Anchored = true
    part.CanCollide = false
    part.Transparency = 1
    part.Size = Vector3.new(1, 1, 1)
    part.CFrame = CFrame.new(pos + Vector3.new(0, 4, 0))
    part.Parent = Workspace
    local g = Instance.new("BillboardGui")
    g.Size = UDim2.new(0, 200, 0, 80)
    g.AlwaysOnTop = true
    g.Parent = part
    local l = Instance.new("TextLabel")
    l.Size = UDim2.fromScale(1, 1)
    l.BackgroundTransparency = 1
    l.Text = "+" .. amount
    l.Font = Enum.Font.GothamBlack
    l.TextScaled = true
    l.TextSize = 36
    l.TextColor3 = Color3.fromRGB(0, 255, 100)
    l.TextStrokeTransparency = 0
    l.TextStrokeColor3 = Color3.new(0, 0, 0)
    l.Parent = g
    task.spawn(function()
        for i = 1, 30 do
            if not part.Parent then return end
            part.CFrame = part.CFrame + Vector3.new(0, 0.15, 0)
            l.TextTransparency = i/30
            l.TextStrokeTransparency = i/30 * 0.7
            task.wait(0.05)
        end
        if part.Parent then part:Destroy() end
    end)
end

-- Listen on the dedicated PrankNPCs / AmbientCrowd folders only (was hooked
-- on Workspace.DescendantAdded which fired for terrain, particle effects, etc.)
local NPC_FOLDERS = {"PrankNPCs", "AmbientCrowd"}

local function watchNpc(npc)
    if not npc:IsA("Model") then return end
    if not npc:GetAttribute("KittyRaiserNPC") then return end
    npc:GetAttributeChangedSignal("Pranked"):Connect(function()
        if not npc:GetAttribute("Pranked") then return end
        local prim = npc.PrimaryPart or npc:FindFirstChild("HumanoidRootPart")
        if not prim then return end
        local pos = prim.Position
        local closestPlayerPos = pos + Vector3.new(0, 0, 5)
        local closestDist = math.huge
        for _, p in ipairs(Players:GetPlayers()) do
            if p.Character and p.Character.PrimaryPart then
                local d = (p.Character.PrimaryPart.Position - pos).Magnitude
                if d < closestDist then
                    closestDist = d
                    closestPlayerPos = p.Character.PrimaryPart.Position
                end
            end
        end
        ragdoll(npc, closestPlayerPos)
        spawnCoinLoot(pos, math.random(3, 6))
        spawnChaosNumber(pos, math.random(20, 80))
    end)
end

for _, folderName in ipairs(NPC_FOLDERS) do
    local folder = Workspace:FindFirstChild(folderName)
    if folder then
        for _, child in ipairs(folder:GetChildren()) do watchNpc(child) end
        folder.ChildAdded:Connect(watchNpc)
    end
end

-- If the folders are created later, attach when they appear.
Workspace.ChildAdded:Connect(function(child)
    if not child:IsA("Folder") then return end
    if not table.find(NPC_FOLDERS, child.Name) then return end
    for _, c in ipairs(child:GetChildren()) do watchNpc(c) end
    child.ChildAdded:Connect(watchNpc)
end)

print("[RagdollOnPrank] ready - NPCs ragdoll + drop coins on prank")

]])

